function.body:
v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Record_ID VARCHAR2(32);
  v_Result NUMBER:=0; --OBTG:NUMBER--
  v_AD_User_ID VARCHAR2(32);
  v_AD_Org_ID VARCHAR2(32);
  v_AD_Client_ID VARCHAR2(32);
  -- Parameter
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Consumption RECORD;
    Cur_Payment RECORD;
    Cur_Rel_Cost RECORD; 
    Cur_Rel_Rev RECORD;

    -- Parameter Variables
    v_Total NUMBER; --OBTG:NUMBER--
   v_Line NUMBER:=0; --OBTG:NUMBER--
   v_CountConsumption NUMBER:=0; --OBTG:NUMBER--
   v_CountPayment NUMBER:=0; --OBTG:NUMBER--
   v_NoInserted NUMBER:=0; --OBTG:NUMBER--
   v_NoInserted2 NUMBER:=0; --OBTG:NUMBER--

   v_Docstatus	VARCHAR(1);
   v_IsLiquidated VARCHAR(1);
   v_TypeLiquidation VARCHAR(60);
   v_DocstatusList VARCHAR(60);
   v_Docstatus2	VARCHAR(60);
   v_TotalCost NUMBER(12,5):=0; --OBTG:NUMBER--
   v_TotalPay NUMBER(12,5):=0; --OBTG:NUMBER--
   v_C_CosCenterID VARCHAR2(32);
   v_PaymentDoc VARCHAR2(32);
   v_LiqDoc VARCHAR2(32);
   v_MSGDoc TEXT;
   v_Count_Paymet NUMBER(12,5):=0; --OBTG:NUMBER--
   v_Count_Consumption NUMBER(12,5):=0; --OBTG:NUMBER--

   v_Cost_Total NUMBER(12,5):=0; --OBTG:NUMBER--
   v_Total_Revenue NUMBER(12,5):=0; --OBTG:NUMBER--

   v_count NUMBER(12,5):=0; --OBTG:NUMBER--
   p_result VARCHAR2(32);
   p_message   VARCHAR2(60);

  BEGIN
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
   BEGIN --BODY

    -- Get Parameters
    v_ResultStr:='ReadingParameters';
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        i.AD_USER_ID,
        i.AD_ORG_ID,
        i.AD_CLIENT_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
        ON i.AD_PInstance_ID=p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID=p_PInstance_ID
      ORDER BY p.SeqNo

      )
    LOOP
      v_Record_ID:=Cur_Parameter.Record_ID;
      v_AD_User_ID:=Cur_Parameter.AD_User_ID;
      v_AD_Org_ID:=Cur_Parameter.AD_Org_ID;
      v_AD_Client_ID:=Cur_Parameter.AD_Client_ID;

     END LOOP; -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_Record_ID) ;
    v_ResultStr:='CheckRestriction';


    SELECT liquidate, type_liquidation, c_costcenter_id,docstatuslist
    into v_Docstatus, v_TypeLiquidation, v_C_CosCenterID, v_DocstatusList
    FROM SSTPC_LIQUIDATION_PROJECTS 
    WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID;

    -- Contar lineas de consumos
    SELECT COALESCE((SELECT COUNT(*) 
    FROM SSTPC_CONSUMPTION_LINE WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID),0) 
    INTO v_Count_Consumption FROM DUAL;

    -- Contar lineas de pagos
    SELECT COALESCE((SELECT COUNT(*) 
    FROM SSTPC_PAYMENT WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID),0) 
    INTO v_Count_Paymet FROM DUAL;

-- Contar lineas de pagos
    SELECT COALESCE((SELECT COUNT(*) 
    FROM SSTPC_PAYMENT WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID),0) 
    INTO v_Count_Paymet FROM DUAL;


    IF (v_Count_Consumption=0) THEN

	v_Message:= '@No se puede liquidar porque no tiene líneas de Consumos@';
        AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_Message) ;
	RETURN;

    END IF;

	-- BEGIN Extension Point
    SELECT count(*) INTO v_count FROM DUAL
    WHERE EXISTS (SELECT 1 FROM ad_ep_procedures WHERE ad_extension_points_id = 'A221C9F383544AC5BC37D3BC17734E6F');
    IF (v_count=1) THEN
      DECLARE
        v_ep_instance VARCHAR2(32);
        v_extension_point_id VARCHAR2(32) := 'A221C9F383544AC5BC37D3BC17734E6F';
      BEGIN
        v_ep_instance := get_uuid();
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID', v_Record_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User', v_AD_User_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
        SELECT p_number INTO p_result
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Result';
        SELECT p_text INTO p_message
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Message';

        DELETE FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance;
      END;
    END IF;
    -- END Extension Point

    IF (v_DocstatusList='DR') THEN 

	    IF (v_Docstatus='N') THEN
		v_IsLiquidated:='Y';
		v_Docstatus2:= 'CO';
	    ELSE
		IF (v_Docstatus='Y') THEN
			v_IsLiquidated:='N';
			v_Docstatus2:= 'LQ';
		END IF;   
	    END IF;

	    FOR Cur_Consumption IN(

		SELECT SCL.M_INOUTLINE_ID,costconsumption as costo
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_CONSUMPTION_LINE SCL ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SCL.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE SLP.SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID
		AND SCL.liquidate='Y'
	    )
	    LOOP

	    		SELECT 
		COALESCE((SELECT to_char(SP.LINE) as line
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_CONSUMPTION_LINE SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.M_INOUTLINE_ID=Cur_Consumption.M_INOUTLINE_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.LIQUIDATE='Y'
		),'ND')
		INTO v_PaymentDoc
		FROM DUAL;

		SELECT 
		COALESCE((SELECT SLP.DOCUMENTNO 
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_CONSUMPTION_LINE SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.M_INOUTLINE_ID=Cur_Consumption.M_INOUTLINE_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.LIQUIDATE='Y'
		),'ND')
		INTO v_LiqDoc
		FROM DUAL;

		IF (v_PaymentDoc<>'ND') THEN
			    v_Message:= '@Consumos - La línea Nro. ' || v_PaymentDoc || ' se encuentra Procesada en la Liquidación Nro.:' || v_LiqDoc || '@'; 
			    Raise Exception '%', v_Message; --OBTG:-20000--
		END IF;

		UPDATE M_INOUTLINE SET EM_SSTPC_ISLIQUIDATED='Y' WHERE M_INOUTLINE_ID = Cur_Consumption.M_INOUTLINE_ID;
		v_NoInserted2:= v_NoInserted2 +1;

		v_TotalCost:= v_TotalCost + Cur_Consumption.costo;

	   END LOOP;

	    FOR Cur_Payment IN(
		SELECT SP.FIN_PAYMENT_SCHEDULEDETAIL_ID, SP.amount as monto
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_PAYMENT SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		where SLP.SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID
		AND SP.isliquidate='Y'
	    )
	    LOOP

		SELECT 
		COALESCE((SELECT to_char(SP.LINE) as line
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_PAYMENT SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.FIN_PAYMENT_SCHEDULEDETAIL_ID=Cur_Payment.FIN_PAYMENT_SCHEDULEDETAIL_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.ISLIQUIDATE='Y'
		),'ND')
		INTO v_PaymentDoc
		FROM DUAL;

		SELECT 
		COALESCE((SELECT SLP.DOCUMENTNO 
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_PAYMENT SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.FIN_PAYMENT_SCHEDULEDETAIL_ID=Cur_Payment.FIN_PAYMENT_SCHEDULEDETAIL_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.ISLIQUIDATE='Y'

		),'ND')
		INTO v_LiqDoc
		FROM DUAL;

		IF (v_PaymentDoc<>'ND') THEN
			    v_Message:= '@Pagos - La línea Nro. ' || v_PaymentDoc || ' se encuentra Procesada en la Liquidación Nro.:' || v_LiqDoc || '@'; 
			    Raise Exception '%', v_Message; --OBTG:-20000--
		END IF;

		UPDATE FIN_PAYMENT_SCHEDULEDETAIL SET EM_SSTPC_ISLIQUIDATED='Y' WHERE FIN_PAYMENT_SCHEDULEDETAIL_ID = Cur_Payment.FIN_PAYMENT_SCHEDULEDETAIL_ID;

		v_NoInserted:= v_NoInserted +1;

		v_TotalPay:= v_TotalPay + Cur_Payment.monto;


	    END LOOP;  


	    --- Liquidar Ingresos Relacionados 


	    FOR Cur_Rel_Rev IN(

		SELECT C_INVOICE_ID,amount
		FROM SSTPC_RELATED_REVENUE
		WHERE  ISLIQUIDATE = 'Y' 
		AND SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID

	    )
	    LOOP

		SELECT 
		COALESCE((SELECT to_char(SP.LINE) as line
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_RELATED_REVENUE SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.C_INVOICE_ID=Cur_Rel_Rev.C_INVOICE_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.ISLIQUIDATE='Y'
		),'ND')
		INTO v_PaymentDoc
		FROM DUAL;

		SELECT 
		COALESCE((SELECT SLP.DOCUMENTNO 
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_RELATED_REVENUE SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.C_INVOICE_ID=Cur_Rel_Rev.C_INVOICE_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.ISLIQUIDATE='Y'

		),'ND')
		INTO v_LiqDoc
		FROM DUAL;

		IF (v_PaymentDoc<>'ND') THEN
			    v_Message:= '@Ingresos Relacionados - La línea Nro. ' || v_PaymentDoc || ' se encuentra Procesada en el Ingreso Nro.:' || v_LiqDoc || '@'; 
			    Raise Exception '%', v_Message; --OBTG:-20000--
		END IF;

		UPDATE C_INVOICE SET EM_SSTPC_LIQUIDATE='Y' WHERE C_INVOICE_ID = Cur_Rel_Rev.C_INVOICE_ID;

		v_Total_Revenue :=v_Total_Revenue  + Cur_Rel_Rev.amount;

		v_NoInserted:= v_NoInserted +1;

	    END LOOP;  


	    --- FIN Liquidar Ingresos Relacionados


	    --- Costos Relacionados

	    FOR Cur_Rel_Cost IN(

		SELECT C_INVOICELINE_ID,Amount
		FROM SSTPC_RELATED_COSTS
		WHERE ISLIQUIDATE = 'Y' 
		AND SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID

	    )
	    LOOP 

		SELECT 
		COALESCE((SELECT to_char(SP.LINE) as line
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_RELATED_COSTS SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.C_INVOICELINE_ID=Cur_Rel_Cost.C_INVOICELINE_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.ISLIQUIDATE='Y'
		),'ND')
		INTO v_PaymentDoc
		FROM DUAL;

		SELECT 
		COALESCE((SELECT SLP.DOCUMENTNO 
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_RELATED_COSTS SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		WHERE docstatuslist='LQ' AND SP.C_INVOICELINE_ID = Cur_Rel_Cost.C_INVOICELINE_ID
		AND SLP.SSTPC_LIQUIDATION_PROJECTS_ID<>v_Record_ID
		AND SP.ISLIQUIDATE='Y'

		),'ND')
		INTO v_LiqDoc
		FROM DUAL;

		IF (v_PaymentDoc<>'ND') THEN
			    v_Message:= '@Costos Relacionados - La línea Nro. ' || v_PaymentDoc || ' se encuentra Procesada en el Costo Relacionado Nro.:' || v_LiqDoc || '@'; 
			    Raise Exception '%', v_Message; --OBTG:-20000--
		END IF;

		UPDATE C_INVOICELINE SET EM_SSTPC_LIQUIDATE=v_IsLiquidated WHERE C_INVOICELINE_ID = Cur_Rel_Cost.C_INVOICELINE_ID;

		v_NoInserted:= v_NoInserted +1;


		v_Cost_Total:= v_Cost_Total +  Cur_Rel_Cost.amount ;


	    END LOOP;  



	    --- FIN Costos Relacionados

	    v_Message:= v_NoInserted2 || ' ' || '@RowsUpdated@' || '- Consumo' || '</br>' || v_NoInserted || ' ' || '@RowsUpdated@' || '- Pagos'; --'@Inserted@=' || v_NoInserted ;--|| ', @Updated@=' || v_NoUpdated;
	    --v_Result:=1; --    success

	    UPDATE  SSTPC_LIQUIDATION_PROJECTS 
	    SET liquidate = (case v_Docstatus when 'Y' then to_char('N') else to_char('Y') end)
	    , docstatus = v_Docstatus2
	    ,processed='Y'
	    ,TOTAL_COST=v_TotalCost
	    ,TOTAL_PAY=v_TotalPay
	    ,COST_TOTAL = v_Cost_Total
	    ,TOTAL_PAYMENTIN = v_Total_Revenue
	    ,docstatuslist='LQ'
	    WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID;

	    UPDATE C_COSTCENTER 
	    SET EM_SSTPC_ISLIQUIDATED = (case when v_TypeLiquidation='TL' then to_char('Y') else to_char('N') end)
	    WHERE C_COSTCENTER_ID = v_C_CosCenterID;


    END IF ; 
	--Desactivar Centro de costos cuando la liquidacion sea Total.
    UPDATE C_Costcenter SET isactive='N'
	WHERE C_Costcenter_id = (SELECT C_Costcenter_id FROM sstpc_liquidation_projects WHERE sstpc_liquidation_projects_id = v_Record_ID AND Type_Liquidation = 'TL' );


 -- BEGIN Extension Point
    SELECT count(*) INTO v_count FROM DUAL
    WHERE EXISTS (SELECT 1 FROM ad_ep_procedures WHERE ad_extension_points_id = '6D2117F92889482FB3BFBE648DB4182B');
    IF (v_count=1) THEN
      DECLARE
        v_ep_instance VARCHAR2(32);
        v_extension_point_id VARCHAR2(32) := '6D2117F92889482FB3BFBE648DB4182B';
      BEGIN
        v_ep_instance := get_uuid();
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID', v_Record_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User', v_AD_User_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
        SELECT p_number INTO p_result
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Result';
        SELECT p_text INTO p_message
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Message';

        DELETE FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance;
      END;
    END IF;
    -- END Extension Point




    -------------------
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 1, v_Message) ;
    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
   ROLLBACK;
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  RETURN;
END SSTPC_LIQUIDATE
